import React from "react";

export const DashboardContent = (props) => {
  const data = props.data;
  return (
    <div>
      {props.pagecontent === "none" ? (
        <div className="w-[90%] bg-[#845EC2] ">
          
        </div>
      ) : (
        <div className="w-[90%] bg-[#845EC2] ">
          <div className="w-[90%]">
            {data.map((item) => {
              return item.id === props.pagecontent ? (
                <div>{item.title}</div>
              ) : null;
            })}
          </div>
        </div>
      )}

      {/* {props.pagecontent === "none" ? (
        <div>None</div>
      ) : (
        data.map((item) => {
          return item.id === props.pagecontent ? (
            <div>{item.content}</div>
          ) : null;
        })
      )} */}
    </div>
  );
};
